<template>
    <div :class="['m-important-msg', { hasMsg: html != '' && !show }]">
        <div class="m-msg-box">
            <span class="u-title">{{ $t("index.importantMsg.title") }}</span>
            <div class="u-content" v-html="html"></div>
            <div class="u-button">
                <el-button @click="confirm" icon="Check" type="primary">{{ $t("index.importantMsg.confirm") }}</el-button>
            </div>
        </div>
    </div>
</template>

<script>
import { getBreadcrumb } from "@jx3box/jx3box-common/js/system";
import User from "@jx3box/jx3box-common/js/user";
export default {
    name: "importantMsg",
    components: {},

    data() {
        return {
            html: "",
            confirm_msg: false,
        };
    },
    computed: {
        userList() {
            const list = this.$store.state.config.user_important_msg || "";
            return list.split(",");
        },
        userId() {
            return User.getInfo().uid;
        },
        hasMsg() {
            return this.userList.includes(this.userId);
        },
        show() {
            const local = localStorage.getItem("confirm_msg");
            return local == 1 || this.confirm_msg;
        },
    },
    watch: {
        hasMsg: {
            immediate: true,
            handler: function (val) {
                val && this.loadData();
            },
        },
    },
    methods: {
        loadData() {
            return getBreadcrumb("user_important_msg").then((res) => {
                this.html = res || "";
            });
        },
        confirm() {
            this.confirm_msg = true;
            localStorage.setItem("confirm_msg", 1);
        },
    },
};
</script>

